import { lazy } from "react";

const About = lazy(() => wait(2000).then(() => import("../components/About")));
const Header = lazy(() =>
  wait(2000).then(() => import("../components/Header"))
);
const Profile = lazy(() =>
  wait(2000).then(() => import("../components/Profile"))
);
const Linked = lazy(() =>
  wait(2000).then(() => import("../components/Linked"))
);
const WaButton = lazy(() =>
  wait(2000).then(() => import("../components/WaButton"))
);
const Home = ({ handleThemeSwitch, theme }) => {
  return (
    <div className="w-full flex flex-col justify-center items-center pb-5">
      <div className="w-[90%] max-w-[720px]">
        <Header handleThemeSwitch={handleThemeSwitch} theme={theme} />
        <Profile />
        <About />
        <Linked />
        <WaButton />
      </div>
    </div>
  );
};

const wait = (time) => {
  return new Promise((resolve) => {
    setTimeout(resolve, time);
  });
};

export default Home;
